(function() { 'use strict'; const keyPressCount = {}; let keyHistory = null; let capsLockLight = null; let scrollLockLight = null; let numLockLight = null; function init() { keyHistory = document.getElementById('key-history'); capsLockLight = document.getElementById('caps-lock-light'); scrollLockLight = document.getElementById('scroll-lock-light'); numLockLight = document.getElementById('num-lock-light'); setupKeyboardListeners(); setupResetButton(); setupHelpButton(); } function setupKeyboardListeners() { document.addEventListener('keydown', handleKeyDown); document.addEventListener('keyup', handleKeyUp); } function handleKeyDown(event) { const key = event.code; const keyElement = document.querySelector(`[data-key="${key}"]`); if (keyElement) { event.preventDefault(); keyPressCount[key] = (keyPressCount[key] || 0) + 1; const activeLevel = ((keyPressCount[key] - 1) % 5) + 1; keyElement.className = keyElement.className.replace(/active-\d/g, '').trim(); keyElement.classList.add(`active-${activeLevel}`); updateKeyCount(keyElement, keyPressCount[key]); if (keyHistory) { const displayKey = getDisplayKey(event); keyHistory.value += displayKey + ' '; keyHistory.scrollTop = keyHistory.scrollHeight; } updateIndicatorLights(key, event); } } function handleKeyUp(event) { } function getDisplayKey(event) { if (event.key === ' ') return '␣'; if (event.key.length > 1) return `[${event.code}]`; return event.key; } function updateKeyCount(keyElement, count) { let keyCountElement = keyElement.querySelector('.key-count'); if (!keyCountElement) { keyCountElement = document.createElement('span'); keyCountElement.className = 'key-count'; keyElement.appendChild(keyCountElement); } keyCountElement.textContent = count; } function updateIndicatorLights(key, event) { if (key === 'CapsLock' && capsLockLight) { capsLockLight.classList.toggle('active'); } if (key === 'ScrollLock' && scrollLockLight) { scrollLockLight.classList.toggle('active'); } if (key === 'NumLock' && numLockLight) { numLockLight.classList.toggle('active'); } } function setupResetButton() { const resetButton = document.getElementById('reset-button'); if (resetButton) { resetButton.addEventListener('click', resetKeyboard); } } function resetKeyboard() { const keys = document.querySelectorAll('.key'); keys.forEach(key => { key.className = key.className.replace(/active-\d/g, '').trim(); const keyCountElement = key.querySelector('.key-count'); if (keyCountElement) { keyCountElement.remove(); } }); if (keyHistory) { keyHistory.value = ''; } if (capsLockLight) capsLockLight.classList.remove('active'); if (scrollLockLight) scrollLockLight.classList.remove('active'); if (numLockLight) numLockLight.classList.remove('active'); for (const key in keyPressCount) { delete keyPressCount[key]; } } function setupHelpButton() { const helpButton = document.getElementById('help-button'); const guidelinesSection = document.getElementById('guidelines') || document.querySelector('.guidelines-section'); if (helpButton && guidelinesSection) { helpButton.addEventListener('click', () => { guidelinesSection.scrollIntoView({ behavior: 'smooth' }); }); } } function checkInitialLockState() { document.addEventListener('keydown', function checkLocks(e) { if (capsLockLight && e.getModifierState('CapsLock')) { capsLockLight.classList.add('active'); } if (numLockLight && e.getModifierState('NumLock')) { numLockLight.classList.add('active'); } if (scrollLockLight && e.getModifierState('ScrollLock')) { scrollLockLight.classList.add('active'); } document.removeEventListener('keydown', checkLocks); }, { once: true }); } if (document.readyState === 'loading') { document.addEventListener('DOMContentLoaded', () => { init(); checkInitialLockState(); }); } else { init(); checkInitialLockState(); } window.KBTKeyboard = { reset: resetKeyboard, getKeyPressCount: (key) => keyPressCount[key] || 0, getAllPresses: () => ({ ...keyPressCount }) }; })();